#include <stdint.h>

#if !defined(__SOFT_FP__) && defined(__ARM_FP)
  #warning "FPU is not initialized, but the project is compiling for an FPU. Please initialize the FPU before use."
#endif

int main(void)
{
	// Enable clock to GPIOC peripheral
	volatile uint32_t *RCC_APB2ENR = (volatile uint32_t *)0x40021018;
	// Configure GPIOC pins 8 to 15
	volatile uint32_t *GPIOC_CRH = (volatile uint32_t *)0x40011004;
	// Control the output state of GPIOC pins
	volatile uint32_t *GPIOC_ODR = (volatile uint32_t *)0x4001100C;

    //enable the 4th pin for GPIOC
	*RCC_APB2ENR |= 0x10;

	/*CNF(configuration) is CNF13 and is at bits 22 and 23 and needs to be 0
	bcz here the reset value 0x44444444 so & it with 0xFF0FFFFF and later the desired config in the CNF13
	same for MODE13 is at bits 20 and 21*/
	*GPIOC_CRH &= 0xFF0FFFFF;

	/*CNFy[1:0]: Port x configuration bits (y= 8 .. 15)
	 * In output mode (MODE[1:0] > 00):
	 CNF13 = 00  -> General Purpose Push-Pull

	  MODEy[1:0]: Port x mode bits (y= 8 .. 15)
	  10: Output mode, max speed 2 MHz.
	   so now its 0x44244444*/
	*GPIOC_CRH |= 0x00200000;


	/*now the 13 bit represents the 13th pin of the port c  */
	while(1)
	{
	    // Turn LED ON (Blue Pill LED is Active LOW)
	    *GPIOC_ODR &= 0x0000DFFF;

	    for(volatile int d = 0; d < 500000; d++);

	    // Turn LED OFF
	    *GPIOC_ODR |= 0x00002000;

	    //the third for loop is for delay
	   /* "d is volatile. I must assume someone outside my program could"
	    " observe or modify it. I cannot remove the loop."*/
	    for(volatile int d = 0; d < 500000; d++);
	}
    /* Loop forever */
	for(;;);
}
